+/**
+ * Checks whether or not a given reference is in the initializer (CallExpression only) of its declared variable.
+ * @param {Reference} reference A reference to check.
+ * @returns {boolean} `true` if the reference is in variable initializer.
+ */
+function hasReferenceInItsInitializer(reference) {
+	const varNode =
+		reference.resolved.defs[0].type === "Variable" &&
+		reference.resolved.defs[0].node;
+	let hasReferenceInInit = false;
+
+	if (
+		varNode &&
+		varNode.type === "VariableDeclarator" &&
+		varNode.init &&
+		varNode.init.type === "CallExpression"
+	) {
+		const funcNodes = varNode.init.arguments.filter(
+			arg =>
+				arg.type === "FunctionExpression" ||
+				arg.type === "ArrowFunctionExpression",
+		);
+		const idLoc = reference.identifier.range;
+
+		if (funcNodes.length > 0) {
+			hasReferenceInInit = funcNodes.some(fn => {
+				const funcBody = fn.body;
+
+				return isInRange(funcBody, idLoc[1]);
+			});
+		}
+
+		const funcCallee = varNode.init.callee;
+
+		if (
+			funcCallee.type === "FunctionExpression" ||
+			funcCallee.type === "ArrowFunctionExpression"
+		) {
+			hasReferenceInInit = isInRange(funcCallee.body, idLoc[1]);
+		}
+
+		if (
+			funcCallee.type === "CallExpression" &&
+			funcCallee.callee.type === "Identifier" &&
+			funcCallee.callee.name === "await" &&
+			funcCallee.arguments.length > 0 &&
+			(funcCallee.arguments[0].type === "FunctionExpression" ||
+				funcCallee.arguments[0].type === "ArrowFunctionExpression")
+		) {
+			hasReferenceInInit = isInRange(
+				funcCallee.arguments[0].body,
+				idLoc[1],
+			);
+		}
+
+		if (
+			funcCallee.type === "MemberExpression" &&
+			funcCallee.object.type === "MemberExpression" &&
+			funcCallee.object.object.type === "ClassExpression" &&
+			funcCallee.object.property.type === "Identifier" &&
+			funcCallee.object.property.name === "prototype"
+		) {
+			if (funcCallee.property.type === "Identifier") {
+				const method = funcCallee.object.object.body.body.find(
+					member =>
+						member.type === "MethodDefinition" &&
+						member.key.type === "Identifier" &&
+						member.key.name === funcCallee.property.name,
+				);
+
+				hasReferenceInInit = isInRange(method, idLoc[1]);
+			}
+		}
+	}
+
+	return hasReferenceInInit;
+}
